const row = items[0].json;
if (!row || !row.id) {
  return [{ json: { valid: false, message: 'Invalid coupon code' } }];
}
if (!row.is_active) {
  return [{ json: { valid: false, message: 'This coupon has been deactivated' } }];
}
if (row.max_uses && row.times_used >= row.max_uses) {
  return [{ json: { valid: false, message: 'This coupon has reached its usage limit' } }];
}
if (row.expires_at && new Date(row.expires_at) < new Date()) {
  return [{ json: { valid: false, message: 'This coupon has expired' } }];
}
return [{
  json: {
    valid: true,
    discount_percent: row.discount_percent,
    affiliate_name: row.affiliate_name,
    coupon_id: row.id
  }
}];
